public OpenMapRealMatrix(int rowDimension, int columnDimension) {
    super(rowDimension, columnDimension);
    if (rowDimension <= 0 || columnDimension <= 0) {
        throw new IllegalArgumentException("Matrix dimensions must be positive and non-zero");
    }
    // Ensure no integer overflow on dimension multiplication
    long totalElements = (long) rowDimension * (long) columnDimension;
    if (totalElements > Integer.MAX_VALUE) {
        throw new org.apache.commons.math.exception.NumberIsTooLargeException(totalElements, Integer.MAX_VALUE, false);
    }
    this.rows = rowDimension;
    this.columns = columnDimension;
    this.entries = new OpenIntToDoubleHashMap(0.0);
}

public OpenMapRealMatrix(int rowDimension, int columnDimension) {
    super(rowDimension, columnDimension);
    if (rowDimension <= 0 || columnDimension <= 0) {
        throw new IllegalArgumentException("Row and column dimensions must be positive");
    }
    // Define a more reasonable dynamic limit for dimensions
    final int maxDimension = (int) Math.sqrt(Integer.MAX_VALUE);
    if (rowDimension > maxDimension || columnDimension > maxDimension) {
        throw new NumberIsTooLargeException(Math.max(rowDimension, columnDimension), maxDimension, true);
    }
    this.rows = rowDimension;
    this.columns = columnDimension;
    this.entries = new OpenIntToDoubleHashMap(0.0);
}
